import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Unknown City",
    temperature = 0,
    condition = "Clear",
    humidity = 0,
    windSpeed = 0,
    unit = "C",
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        {/* Header: City & Condition */}
        <Stack gap={4} align="center">
          <Heading level={2}>{city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-neutral-500, #6b7280)">{condition}</Text>
        </Stack>

        {/* Current Temperature */}
        <Stack align="center" gap={0}>
          <Heading level={1}>
            {temperature}°{unit}
          </Heading>
        </Stack>

        {/* Stats */}
        <Box paddingY={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
              <Text variant="label">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={0} />
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind Speed</Text>
              <Text variant="label">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8} style={{ flex: 1 }}>
              <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">{item.day ?? '—'}</Text>
              <Text as="span" style={{ fontSize: '24px' }}>{item.icon ?? '?'}</Text>
              <Stack gap={0} align="center">
                <Text variant="bodySmall" weight="semibold">{item.high ?? 0}°</Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Box } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: any) => void;
}

export default function GeneratedComponent({
  featureOptions = ["Dashboard Analytics", "Team Collaboration", "API Integration", "Custom Workflows", "Mobile App", "AI Assistance"],
  satisfactionLabels = ["Very Unsatisfied", "Unsatisfied", "Neutral", "Satisfied", "Very Satisfied"],
  onSubmit = (data: any) => console.log('Submitted:', data),
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    satisfaction: null as number | null,
    features: [] as string[],
    comments: "",
  });

  const [errors, setErrors] = useState({ name: "", email: "" });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep1 = () => {
    const newErrors = {
      name: formData.name ? "" : "Name is required",
      email: validateEmail(formData.email) ? "" : "Valid email is required",
    };
    setErrors(newErrors);
    return !newErrors.name && !newErrors.email;
  };

  const nextStep = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => Math.min(s + 1, 5));
  };

  const prevStep = () => setStep((s) => Math.max(s - 1, 1));

  const toggleFeature = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Input 
              label="Name" 
              value={formData.name} 
              onChange={(v) => setFormData({ ...formData, name: v })} 
              error={errors.name} 
              required 
            />
            <Input 
              label="Email" 
              type="email" 
              value={formData.email} 
              onChange={(v) => setFormData({ ...formData, email: v })} 
              error={errors.email} 
              required 
            />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup
            label="How satisfied are you with our product?"
            value={formData.satisfaction?.toString() || ""}
            onChange={(v) => setFormData({ ...formData, satisfaction: parseInt(v) })}
            options={satisfactionLabels.map((label, idx) => ({ value: (idx + 1).toString(), label }))}
          />
        );
      case 3:
        return (
          <Stack gap={8}>
            <Text variant="label">Select features you are interested in:</Text>
            {featureOptions.map((f) => (
              <Checkbox 
                key={f} 
                label={f} 
                checked={formData.features.includes(f)} 
                onChange={() => toggleFeature(f)} 
              />
            ))}
          </Stack>
        );
      case 4:
        return (
          <TextArea
            label="Additional Comments (optional)"
            value={formData.comments}
            onChange={(v) => setFormData({ ...formData, comments: v })}
            maxLength={500}
            showCount
            rows={4}
          />
        );
      case 5:
        return (
          <Stack gap={12}>
            <Heading level={4}>Review your answers</Heading>
            <Box padding={12} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius={8}>
              <Text variant="bodySmall">Name: {formData.name}</Text>
              <Text variant="bodySmall">Email: {formData.email}</Text>
              <Text variant="bodySmall">Satisfaction: {formData.satisfaction ? satisfactionLabels[formData.satisfaction - 1] : "N/A"}</Text>
              <Text variant="bodySmall">Features: {formData.features.join(", ") || "None"}</Text>
              <Text variant="bodySmall">Comments: {formData.comments || "None"}</Text>
            </Box>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Card padding={24} shadow="md">
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="overline">Step {step} of 5</Text>
          <Progress value={(step / 5) * 100} size="sm" />
        </Stack>

        {renderStep()}

        <Stack direction="horizontal" justify="between">
          <Button variant="secondary" onClick={prevStep} disabled={step === 1}>Back</Button>
          {step < 5 ? (
            <Button onClick={nextStep}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit(formData)}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Badge, 
  Avatar, 
  Box 
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Props {
  tasks: Array<Task>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { tasks: initialTasks = [], columns = [], onTaskUpdate } = props;
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail?.tasks) setTasks(event.detail.tasks);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const totalTasks = tasks.length;
  const doneTasks = tasks.filter((t) => t.column === 'done').length;

  const handleTaskMove = (taskId: string | undefined, newColumn: string) => {
    if (!taskId) return;
    const updatedTasks = tasks.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
    setTasks(updatedTasks);
    onTaskUpdate?.({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleCreate = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask: Task = {
      id: Math.random().toString(36).substring(7),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
    };
    setTasks([...tasks, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
    setAddingTo(null);
    setNewTaskTitle('');
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16}>
        <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
          <Text variant="label">Task Summary: {doneTasks} / {totalTasks} Completed</Text>
        </Box>

        <Stack direction="horizontal" gap={16} align="start" wrap>
          {columns.map((col) => (
            <Card key={col.id} padding={16} style={{ width: 320 }}>
              <Stack gap={12}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Heading level={4}>{col.name ?? 'Untitled'}</Heading>
                  <Badge variant="secondary">{tasks.filter((t) => t.column === col.id).length}</Badge>
                </Stack>

                <Stack gap={8}>
                  {tasks
                    .filter((t) => t.column === col.id)
                    .map((task) => (
                      <Card key={task.id} padding={12} shadow="sm">
                        <Stack gap={8}>
                          <Text variant="bodySmall" weight="medium">{task.title}</Text>
                          <Stack direction="horizontal" gap={8} align="center">
                            <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}>
                              {task.priority}
                            </Badge>
                            <Avatar name={task.assignee ?? '??'} size={24} />
                          </Stack>
                          <Select
                            value={task.column ?? ''}
                            onChange={(val) => handleTaskMove(task.id, val)}
                            options={columns.map((c) => ({ value: c.id ?? '', label: `Move to ${c.name}` }))}
                            size="sm"
                          />
                        </Stack>
                      </Card>
                    ))}
                </Stack>

                {addingTo === col.id ? (
                  <Stack gap={8}>
                    <Input value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." size="sm" />
                    <Select
                      value={newTaskPriority}
                      onChange={(v: any) => setNewTaskPriority(v)}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                      size="sm"
                    />
                    <Button onClick={() => handleCreate(col.id ?? '')} size="sm" fullWidth>Add</Button>
                    <Button variant="ghost" size="sm" onClick={() => setAddingTo(null)}>Cancel</Button>
                  </Stack>
                ) : (
                  <Button variant="ghost" size="sm" onClick={() => setAddingTo(col.id ?? null)}>+ Add Task</Button>
                )}
              </Stack>
            </Card>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements?: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-success-200, #bbf7d0)',
  'noble-gas': 'var(--ggui-color-info-200, #a5f3fc)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'post-transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'metalloid': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'lanthanide': 'var(--ggui-color-neutral-300, #d1d5db)',
  'actinide': 'var(--ggui-color-neutral-300, #d1d5db)',
};

const DEFAULT_COLOR = 'var(--ggui-color-neutral-100, #f3f4f6)';

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const lowerSearch = search.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(lowerSearch) ||
        e.symbol?.toLowerCase().includes(lowerSearch)
    );
  }, [search, elements]);

  const categories = Array.from(new Set(elements.map((e) => e.category || 'unknown')));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Input 
          label="Search Elements"
          type="search" 
          value={search} 
          onChange={setSearch} 
          placeholder="Name or Symbol..." 
        />

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto'
          }}
        >
          {elements.map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <Box
                key={el.atomicNumber}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  opacity: isVisible ? 1 : 0.2,
                  transition: 'opacity 0.2s',
                }}
              >
                <Card
                  padding="var(--ggui-spacing-2, 8px)"
                  shadow="sm"
                  border
                  onClick={() => setSelectedElement(el)}
                  style={{
                    backgroundColor: el.category ? (CATEGORY_COLORS[el.category] || DEFAULT_COLOR) : DEFAULT_COLOR,
                    cursor: 'pointer',
                    minHeight: 'var(--ggui-spacing-12, 48px)',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    height: '100%'
                  }}
                >
                  <Text variant="caption">{el.atomicNumber}</Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'bold', textAlign: 'center' }}>
                    {el.symbol}
                  </Text>
                </Card>
              </Box>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text variant="body">Symbol: {selectedElement.symbol}</Text>
              <Text variant="body">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="body">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}

        <Box>
          <Text variant="label" style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}>Legend</Text>
          <Stack direction="horizontal" wrap gap="var(--ggui-spacing-3, 12px)">
            {categories.map(cat => (
              <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                <Box style={{ width: 16, height: 16, backgroundColor: CATEGORY_COLORS[cat] || DEFAULT_COLOR, borderRadius: '4px' }} />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Divider, 
  Text, 
  Heading, 
  Button, 
  Badge, 
  Icon, 
  Tabs 
} from '@ggui-ai/design/primitives';
import { FormField, Input } from '@ggui-ai/design/components';

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Product {
  id?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
}

interface Props {
  product: Product;
  onAddToCart: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: 'prod-001',
    name: 'Wireless Noise-Cancelling Headphones',
    price: 249.99,
    currency: 'USD',
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: 'Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.',
    specifications: [
      { key: 'Brand', value: 'AudioMax' },
      { key: 'Battery Life', value: '30 hours' }
    ],
    reviews: [
      { author: 'Alex M.', rating: 5, text: 'Best headphones I have ever owned.', date: '2026-03-01' }
    ]
  },
  onAddToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleAddToCart = async () => {
    if (!product.id) return;
    setIsSubmitting(true);
    await onAddToCart({ productId: product.id, quantity });
    setIsSubmitting(false);
  };

  const renderStars = (rating: number = 0) => (
    <Stack direction="horizontal" gap={2}>
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon 
          key={star} 
          name={star <= Math.round(rating) ? 'check' : 'minus'} 
          size={16} 
          color={star <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'} 
        />
      ))}
    </Stack>
  );

  const tabs = [
    {
      key: 'desc',
      label: 'Description',
      content: <Text variant="body">{product.description ?? 'No description available.'}</Text>
    },
    {
      key: 'specs',
      label: 'Specifications',
      content: (
        <Stack gap={8}>
          {(product.specifications ?? []).map((spec: any, i: number) => (
            <Stack key={i} direction="horizontal" gap={16}>
              <Text weight="semibold" style={{ minWidth: 120 }}>{spec.key}</Text>
              <Text>{spec.value}</Text>
            </Stack>
          ))}
        </Stack>
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap={16}>
          {(product.reviews ?? []).map((review: any, i: number) => (
            <Box key={i} paddingY={8} style={{ borderBottom: '1px solid var(--ggui-color-neutral-200)' }}>
              <Stack gap={4}>
                <Text weight="semibold">{review.author} • {review.date}</Text>
                {renderStars(review.rating)}
                <Text>{review.text}</Text>
              </Stack>
            </Box>
          ))}
        </Stack>
      )
    }
  ];

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box 
            style={{ 
              width: '100%', maxWidth: 400, height: 400, 
              background: 'var(--ggui-color-neutral-200)',
              display: 'flex', alignItems: 'center', justifyContent: 'center'
            }}
            borderRadius={12}
          >
            <Heading level={3}>{product.name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1 }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{product.currency} {product.price?.toFixed(2)}</Text>

            <Stack direction="horizontal" align="center" gap={8}>
              {renderStars(product.rating)}
              <Text variant="caption">({product.reviewCount ?? 0} reviews)</Text>
            </Stack>

            <Badge variant={product.stock && product.stock > 0 ? 'success' : 'error'}>
              {product.stock && product.stock > 0 ? (product.stock > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>

            <Divider />

            <Stack direction="horizontal" align="center" gap={16}>
              <Box>
                <FormField label="Quantity">
                  <Input 
                    label="Quantity"
                    type="number" 
                    value={quantity.toString()} 
                    onChange={(v) => setQuantity(Math.max(1, Math.min(product.stock ?? 1, parseInt(v) || 1)))} 
                  />
                </FormField>
              </Box>
              <Button 
                variant="primary" 
                size="lg" 
                disabled={!product.stock || product.stock === 0 || isSubmitting}
                loading={isSubmitting}
                onClick={handleAddToCart}
              >
                Add to Cart
              </Button>
            </Stack>
          </Stack>
        </Stack>

        <Divider />

        <Card shadow="none" padding={0}>
          <Tabs items={tabs} />
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Text, Heading, Divider, Input, Button, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages: initialMessages } = props;
  const [messages, setMessages] = useState(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages(initialMessages);
  }, [initialMessages]);

  useEffect(() => {
    const listener = (event: any) => {
      const data = event.detail;
      if (data && data.sender && data.text) {
        setMessages((prev) => [...prev, data]);
      }
    };
    window.addEventListener('ggui:agent-data', listener);
    return () => window.removeEventListener('ggui:agent-data', listener);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (inputValue.trim()) {
      const newMessage = {
        sender: currentUser,
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      setMessages([...messages, newMessage]);
      setInputValue('');
      // Trigger side-effect/callback logic
    }
  };

  return (
    <Card padding={0} shadow="md" radius="lg" border={true}>
      <Stack gap={0}>
        <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-2, 8px)" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Heading level={3}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="secondary">{participantCount} participants</Badge>}
        </Box>
        <Divider margin={0} />
        <Box ref={scrollRef} padding="var(--ggui-spacing-4, 16px)" style={{ height: '400px', overflowY: 'auto' }}>
          <Stack gap="var(--ggui-spacing-2, 8px)">
            {messages.map((msg, index) => {
              const isMine = msg.sender === currentUser;
              return (
                <Box key={index} style={{ 
                  display: 'flex', 
                  justifyContent: isMine ? 'flex-end' : 'flex-start',
                  marginTop: 'var(--ggui-spacing-2, 8px)'
                }}>
