import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Heading, Divider, Spinner, Icon } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: Stock[];
  lastUpdated?: string;
}

const StockCard: React.FC<Stock> = ({ symbol, name, price, change, changePercent }) => {
  const isPositive = (change ?? 0) >= 0;
  const color = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

  return (
    <Card 
      padding={20} 
      shadow="sm" 
      radius="md" 
      border={true}
    >
      <Stack gap={8}>
        <Stack direction="horizontal" justify="between" align="center">
          <Text weight="bold" size="xl">{symbol ?? 'N/A'}</Text>
          <Text weight="semibold" size="lg">${(price ?? 0).toFixed(2)}</Text>
        </Stack>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{name ?? 'Unknown'}</Text>
        <Stack direction="horizontal" gap={4} align="center">
          <Icon name={isPositive ? 'chevron-up' : 'chevron-down'} size={16} color={color} />
          <Text weight="medium" color={color}>
            {Math.abs(change ?? 0).toFixed(2)} ({Math.abs(changePercent ?? 0).toFixed(2)}%)
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
};

export default function GeneratedComponent(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialLastUpdated } = props;
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState(initialLastUpdated);

  useEffect(() => {
    const handleData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { symbol, price, change, changePercent } = customEvent.detail;

      setStocks((prev) =>
        prev.map((s) => (s.symbol === symbol ? { ...s, price, change, changePercent } : s))
      );
      setLastUpdated(new Date().toISOString());
    };

    window.addEventListener('ggui:agent-data', handleData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handleData as EventListener);
    };
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>
        <Divider />
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
          gap: 'var(--ggui-spacing-4)' 
        }}>
          {stocks.map((stock, idx) => (
            <StockCard key={stock.symbol ?? idx} {...stock} />
          ))}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Checkbox, Toggle, Divider, Container, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called when the user completes onboarding */
  onComplete: (data: any) => void;
}

export default function GeneratedComponent({ 
  initialProfile = {}, 
  avatarOptions, 
  roleOptions,
  onComplete 
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions[0] ?? ''),
    role: initialProfile.role ?? (roleOptions[0] ?? ''),
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light'
  });

  const [errors, setErrors] = useState<{ email?: string; name?: string }>({});

  const validateStep1 = () => {
    const newErrors: typeof errors = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = 'Valid email is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => Math.min(s + 1, 3));
  };

  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24} radius="lg" shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={3}>Step {step} of 3</Heading>
            <Box background="var(--ggui-color-neutral-200, #e5e7eb)" borderRadius={4} paddingY={4} style={{ width: '100%', overflow: 'hidden' }}>
              <div style={{ 
                width: `${(step / 3) * 100}%`, 
                height: '8px', 
                background: 'var(--ggui-color-primary-600, #0284c7)',
                borderRadius: '4px',
                transition: 'width 0.3s ease'
              }} />
            </Box>
          </Stack>

          {step === 1 && (
            <Stack gap={16}>
              <Heading level={4}>Profile Setup</Heading>
              <Input label="Name" value={formData.name} onChange={(v) => setFormData(p => ({...p, name: v}))} required error={errors.name} />
              <Input label="Email" value={formData.email} onChange={(v) => setFormData(p => ({...p, email: v}))} required error={errors.email} type="email" />
              <Stack gap={8}>
                <Text variant="label">Avatar</Text>
                <Stack direction="horizontal" gap={8}>
                  {avatarOptions.map(opt => (
                    <Button 
                      key={opt} 
                      variant={formData.avatar === opt ? 'primary' : 'outline'}
                      onClick={() => setFormData(p => ({...p, avatar: opt}))}
                    >{opt}</Button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={4}>Preferences</Heading>
              <Select 
                label="Role" 
                value={formData.role} 
                onChange={(v) => setFormData(p => ({...p, role: v}))}
                options={roleOptions.map(r => ({ label: r, value: r }))}
              />
              <Checkbox label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData(p => ({...p, emailNotifications: v}))} />
              <Toggle label={`Dark Mode: ${formData.theme === 'dark' ? 'On' : 'Off'}`} checked={formData.theme === 'dark'} onChange={(v) => setFormData(p => ({...p, theme: v ? 'dark' : 'light'}))} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Review & Confirm</Heading>
              <Box padding={16} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius={8}>
                <Stack gap={8}>
                  <Text variant="bodySmall"><strong>Name:</strong> {formData.name}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {formData.email}</Text>
                  <Text variant="bodySmall"><strong>Role:</strong> {formData.role}</Text>
                  <Text variant="bodySmall"><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

