import React, { useState } from 'react';
import { Container, Card, Stack, Text, Heading, Divider, Box, Spacer } from '@ggui-ai/design/primitives';
import { Input, TextArea, RadioGroup, Checkbox, Button, Progress } from '@ggui-ai/design/components';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      "Dashboard Analytics",
      "Team Collaboration",
      "API Integration",
      "Custom Workflows",
      "Mobile App",
      "AI Assistance"
    ],
    satisfactionLabels = [
      "Very Unsatisfied",
      "Unsatisfied",
      "Neutral",
      "Satisfied",
      "Very Satisfied"
    ]
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = () => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 2) return formData.satisfaction !== '';
    return true;
  };

  const steps = 4;

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData(prev => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature] 
        : prev.features.filter(f => f !== feature)
    }));
  };

  const handleSubmit = () => {
    console.log('Submitting:', JSON.stringify(formData));
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Customer Satisfaction Survey</Heading>
          <Progress value={(step / steps) * 100} variant="primary" size="sm" />
          <Text variant="caption">Step {step} of {steps}</Text>
        </Stack>

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={3}>Personal Information</Heading>
              <Input 
                label="Full Name" 
                value={formData.name} 
                onChange={(v) => setFormData({...formData, name: v})} 
                required 
              />
              <Input 
                label="Email Address" 
                type="email"
                value={formData.email} 
                onChange={(v) => setFormData({...formData, email: v})} 
                error={formData.email && !isEmailValid(formData.email) ? "Invalid email format" : undefined}
                required 
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup 
                label="How satisfied are you with our service?"
                value={formData.satisfaction}
                onChange={(v) => setFormData({...formData, satisfaction: v})}
                options={satisfactionLabels.map((label, i) => ({ value: (i + 1).toString(), label }))}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="bodySmall">Select the features you are most interested in:</Text>
              {featureOptions.map(option => (
                <Checkbox 
                  key={option}
                  label={option}
                  checked={formData.features.includes(option)}
                  onChange={(c) => handleFeatureToggle(option, c)}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap={16}>
              <Heading level={3}>Comments</Heading>
              <TextArea 
                label="Additional Feedback"
                value={formData.comments}
                onChange={(v) => setFormData({...formData, comments: v})}
                maxLength={500}
                showCount
                rows={4}
              />
              <Divider />
              <Heading level={4}>Review Your Answers</Heading>
              <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
                <Stack gap={8}>
                  <Text variant="bodySmall">Name: {formData.name}</Text>
                  <Text variant="bodySmall">Email: {formData.email}</Text>
                  <Text variant="bodySmall">Satisfaction: {formData.satisfaction}/5</Text>
                  <Text variant="bodySmall">Features: {formData.features.join(', ')}</Text>
                </Stack>
              </Box>
            </Stack>
          )}

          <Spacer size={24} />

          <Stack direction="horizontal" gap={16} justify="between">
            <Button 
              variant="secondary" 
              onClick={() => setStep(s => s - 1)} 
              disabled={step === 1}
            >
              Back
            </Button>
            {step < steps ? (
              <Button 
                variant="primary" 
                onClick={() => setStep(s => s + 1)} 
                disabled={!canGoNext()}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>Submit</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Box, Spacer } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Props {
  tasks: Task[];
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent({ tasks: initialTasks, columns, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');

  const handleUpdate = (action: string, taskId: string, data: any) => {
    onTaskUpdate?.({ action, taskId, data });
    if (action === 'move') {
      setTasks(tasks.map(t => t.id === taskId ? { ...t, ...data } : t));
    }
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: 'medium',
      column: columnId,
    };
    setTasks([...tasks, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id!, data: newTask });
    setNewTaskTitle('');
    setAddingTo(null);
  };

  const completedCount = tasks.filter(t => t.column === 'done').length;

  return (
    <Box padding={24}>
      <Stack direction="horizontal" justify="between" style={{ marginBottom: '24px' }}>
        <Heading level={2}>Kanban Board</Heading>
        <Text variant="bodySmall">Total: {tasks.length} | Done: {completedCount}</Text>
      </Stack>

      <Stack direction="horizontal" gap={24} align="start">
        {columns.map((col) => (
          <Box key={col.id} style={{ flex: 1, minWidth: '300px' }} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius="lg">
            <Stack gap={16}>
              <Heading level={4}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>

              <Stack gap={12}>
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={12}>
                    <Stack gap={8}>
                      <Text variant="label">{task.title}</Text>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="caption">{task.priority} • {task.assignee}</Text>
                        <Select 
                          value={task.column} 
                          onChange={(val) => handleUpdate('move', task.id!, { column: val })}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                          size="sm"
                        />
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {addingTo === col.id ? (
                <Stack gap={8}>
                  <Input value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." />
                  <Button size="sm" onClick={() => handleAddTask(col.id!)}>Add Task</Button>
                </Stack>
              ) : (
                <Button variant="ghost" size="sm" onClick={() => setAddingTo(col.id!)}>+ Add Task</Button>
              )}
            </Stack>
          </Box>
        ))}
      </Stack>
    </Box>
  );
}

