const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-success-200, #bbf7d0)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'halogen': 'var(--ggui-color-error-200, #fecaca)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'metalloid': 'var(--ggui-color-info-100, #cffafe)',
  'lanthanide': 'var(--ggui-color-neutral-300, #d1d5db)',
  'actinide': 'var(--ggui-color-neutral-400, #9ca3af)',
};

