  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  product: { 
    id?: string; 
    name?: string; 
    price?: number; 
    currency?: string; 
    rating?: number; 
    reviewCount?: number; 
    stock?: number; 
    description?: string; 
    specifications?: { key: string; value: string }[]; 
    reviews?: { author: string; rating: number; text: string; date: string }[] 
  };
  addToCart: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({ 
  product = {
    id: "prod-001",
    name: "Wireless Noise-Cancelling Headphones",
    price: 249.99,
    currency: "USD",
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: "Premium wireless headphones with adaptive noise cancellation.",
    specifications: [
      { key: "Brand", value: "AudioMax" },
      { key: "Battery Life", value: "30 hours" }
    ],
    reviews: [
      { author: "Alex M.", rating: 5, text: "Best headphones I have ever owned.", date: "2026-03-01" }
    ]
  },
  addToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const [question, setQuestion] = useState('');
  const [email, setEmail] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formStatus, setFormStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const formatPrice = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(val);

  const handleAddToCart = () => {
    if (product.id) addToCart({ productId: product.id, quantity });
  };

  const handleFormSubmit = async () => {
    if (!question || !email) return;
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setFormStatus('success');
    }, 1000);
  };

  return (
    <Container maxWidth="xl" padding="32px">
      <Stack gap={32}>
        <Stack direction="horizontal" gap={48} align="start" wrap>
          <Box 
            background="var(--ggui-color-primary-50)" 
            borderRadius={16}
            padding={64}
            style={{ flex: '1 1 400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" gap={16}>
              <Icon name="settings" size={64} color="var(--ggui-color-primary-300)" />
              <Text weight="bold" color="var(--ggui-color-primary-700)">{product.name}</Text>
            </Stack>
          </Box>

          <Stack gap={24} style={{ flex: '1 1 300px' }}>
            <Stack gap={8}>
              {product.stock! > 0 ? <Badge variant="success">In Stock</Badge> : <Badge variant="error">Out of Stock</Badge>}
              <Heading level={1}>{product.name}</Heading>
            </Stack>
            <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
              {formatPrice(product.price || 0, product.currency || 'USD')}
            </Text>
            <Stack gap={16}>
              <Text variant="label">Quantity</Text>
              <Stack direction="horizontal" gap={12} align="center">
                <Button variant="outline" size="sm" onPress={() => setQuantity(q => Math.max(1, q - 1))}>
                  <Icon name="minus" size={16} />
                </Button>
                <Text weight="semibold">{quantity}</Text>
                <Button variant="outline" size="sm" onPress={() => setQuantity(q => Math.min(product.stock || 1, q + 1))}>
                  <Icon name="plus" size={16} />
                </Button>
              </Stack>
              <Button variant="primary" size="lg" fullWidth onPress={handleAddToCart} disabled={!product.stock || product.stock <= 0}>
                Add to Cart
              </Button>
            </Stack>
          </Stack>
        </Stack>

        <Card padding={24} shadow="md" radius="xl">
          <Tabs
            variant="line"
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              { key: 'description', label: 'Description', content: <Box paddingY={16}><Text>{product.description}</Text></Box> },
              { key: 'specifications', label: 'Specifications', content: <Box paddingY={16}><Table columns={[{ key: 'key', header: 'Feature' }, { key: 'value', header: 'Detail' }]} data={product.specifications || []} bordered /></Box> },
              { key: 'reviews', label: 'Reviews', content: <Box paddingY={16}><Text>No reviews yet.</Text></Box> }
            ]}
          />
        </Card>

        <Card padding={32} radius="xl" shadow="sm">
          <Stack gap={24}>
            <Heading level={3}>Have a Question?</Heading>
            {formStatus === 'success' ? (
              <Alert variant="success" title="Message Sent" />
            ) : (
              <Stack gap={16}>
                <Input label="Email Address" type="email" value={email} onChange={setEmail} required />
                <TextArea label="Your Question" value={question} onChange={setQuestion} rows={3} required />
                <Button variant="primary" loading={isSubmitting} onPress={handleFormSubmit}>Send Question</Button>
              </Stack>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Stack, Text, Heading, Divider, Box, Spacer } from '@ggui-ai/design/primitives';
import { Input, Button, Avatar } from '@ggui-ai/design/components';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount = 0, messages: initialMessages, onSendMessage } = props;
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setMessages((prev) => [...prev, event.detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const newMessage = {
      sender: currentUser,
      text: inputValue,
      timestamp: new Date().toISOString(),
    };
    setMessages((prev) => [...prev, newMessage]);
    onSendMessage?.({ text: inputValue, timestamp: newMessage.timestamp });
    setInputValue('');
  };

  return (
    <Stack style={{ height: '500px', border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', overflow: 'hidden' }}>
      <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          <Text variant="caption">{participantCount} participants</Text>
        </Stack>
      </Box>

      <Box ref={scrollRef} padding={16} style={{ flex: 1, overflowY: 'auto' }}>
        <Stack gap={12}>
          {messages.map((msg, idx) => {
            const isCurrentUser = msg.sender === currentUser || msg.sender === 'You';
            return (
              <Stack 
                key={idx} 
                direction="horizontal" 
                justify={isCurrentUser ? 'end' : 'start'}
              >
                <Box 
                  paddingX={12} 
                  paddingY={8} 
                  borderRadius={8} 
                  background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                >
                  <Text variant="bodySmall" color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>
                    <strong>{msg.sender}:</strong> {msg.text}
                  </Text>
                  <Text variant="caption" size="xs" color={isCurrentUser ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                    {new Date(msg.timestamp ?? '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </Text>
                </Box>
              </Stack>
            );
          })}
        </Stack>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <Input 
              label="Compose message"
              value={inputValue} 
              onChange={setInputValue} 
              placeholder="Type a message..."
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
          </div>
          <Button onClick={handleSend} disabled={!inputValue.trim()}>
            Send Message
          </Button>
        </Stack>
      </Box>
    </Stack>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Spacer, Divider } from '@ggui-ai/design/primitives';

interface Props {
  stocks?: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const handleData = (event: any) => {
      const { stocks: newStocks, lastUpdated: newTime } = event.detail ?? {};
      if (newStocks) setStocks(newStocks);
      if (newTime) setLastUpdated(newTime);
      setLoading(false);
    };

    window.addEventListener('ggui:agent-data', handleData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleData as EventListener);
  }, []);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Text variant="bodyLarge" weight="bold">Market Watch</Text>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        <Divider />

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)'
        }}>
          {stocks.map((stock, idx) => {
            const change = stock.change ?? 0;
            const isPositive = change >= 0;
            const color = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card key={idx} padding={20} border={true} shadow="sm">
                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" size="2xl" weight="bold">{stock.symbol ?? 'N/A'}</Text>
                    <Text size="lg" weight="semibold">
                      ${stock.price?.toFixed(2) ?? '0.00'}
                    </Text>
                  </Stack>
                  <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                    {stock.name ?? 'Unknown Company'}
                  </Text>
                  <Spacer size={8} />
                  <div style={{ color, display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <Text weight="medium">
                      {isPositive ? '▲' : '▼'} {Math.abs(change).toFixed(2)} ({Math.abs(stock.changePercent ?? 0)}%)
                    </Text>
                  </div>
                </Stack>
              </Card>
            );
          })}
        </div>

        {stocks.length === 0 && (
          <Card padding={40}>
            <Text align="center" color="var(--ggui-color-neutral-500, #6b7280)">
              No stock data available.
            </Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Spacer, Box } from '@ggui-ai/design/primitives';
import { Button, Input, Select, RadioGroup, Toggle, Progress } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? props.avatarOptions[0],
    role: props.initialProfile?.role ?? props.roleOptions[0],
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const canGoNext = step === 1 ? (formData.name !== '' && isEmailValid) : true;

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleSubmit = () => props.onComplete?.(formData);

  return (
    <Card padding={32} shadow="md" border={true} radius="lg">
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={3}>Onboarding ({step}/3)</Heading>
          <Progress value={(step / 3) * 100} size="md" />
        </Stack>

        {step === 1 && (
          <Stack gap={16}>
            <Heading level={4}>Profile Setup</Heading>
            <Input label="Name" required value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} />
            <Input label="Email" required value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} error={formData.email && !isEmailValid ? "Invalid email" : undefined} />
            <Stack direction="horizontal" gap={12} align="center">
              <Text variant="label">Select Avatar:</Text>
              {props.avatarOptions.map((emoji) => (
                <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'secondary'} size="sm" onClick={() => setFormData({ ...formData, avatar: emoji })}>
                  {emoji}
                </Button>
              ))}
            </Stack>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <Heading level={4}>Preferences</Heading>
            <Select label="Role" value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} options={props.roleOptions.map(r => ({ value: r, label: r }))} />
            <Toggle label="Email notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
            <RadioGroup label="Theme" value={formData.theme} onChange={(v) => setFormData({ ...formData, theme: v })} options={[{value: 'light', label: 'Light'}, {value: 'dark', label: 'Dark'}]} />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={16}>
            <Heading level={4}>Review</Heading>
            <Box background="var(--ggui-color-neutral-100)" padding={16} borderRadius={8}>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
              <Text>Avatar: {formData.avatar}</Text>
            </Box>
          </Stack>
        )}

        <Stack direction="horizontal" gap={16} justify="end">
          {step > 1 && <Button variant="secondary" onClick={handleBack}>Go Back</Button>}
          {step < 3 ? (
            <Button disabled={!canGoNext} onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}
